INSERT INTO diagnoses (id, report_id, passed, created_at) VALUES ('8f35b2df0f8b4dd5905eae58d36b69d4', 'f8d92b497b8040e79966fd183e162b95', FALSE, '2026-07-14T11:40:39.842588+00');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('7847d4c799d34327be7216392261ed60', '1188ac41599647a4acff138e1e2fd485', '工作满意度', 'kmo', 0.5, 0.6, 'KMO值仅为0.5，低于可接受阈值0.6，表明变量间的偏相关性较弱，不适合进行因子分析。可能原因包括：该维度题目数量过少（例如少于3题），或题目间共同度较低、存在较多特异性方差，导致整体结构效度不足。', '建议增加该维度的题目数量（至少3-5题），并确保题目内容紧密围绕工作满意度核心概念；同时可删除部分相关性极低的题目，或重新审视题目措辞以提高内部一致性。若样本量较小，可考虑扩大样本。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('852f49ffa144406a9ac48ed205aeb5e8', '1188ac41599647a4acff138e1e2fd485', '职业发展', 'kmo', 0.5, 0.6, 'KMO值为0.5，低于可接受阈值0.6，表明变量间偏相关性较弱，因子分析适用性不足。可能原因包括：该维度题目数量偏少，或题目内容存在歧义、重复度低，导致变量间无法提取公共因子。', '建议优化或扩充该维度题目，确保题目能充分覆盖职业发展的不同方面（如晋升机会、培训支持、职业规划等）；同时进行项目分析，剔除区分度低或与其他题目相关性过弱的题目。如果条件允许，可重新收集数据并检验结构效度。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('4c457fc011ec445cac7124a0d6f8e928', 'b54e294b9cd04196b131da3e55787d2c', '工作满意度', 'kmo', 0.5, 0.6, 'KMO值为0.5，低于0.6的可接受标准，表明该维度内题项之间的偏相关性较强，变量间共同方差较少，可能由于样本量不足、题项间相关性较低或存在无关题项导致因子分析效果不佳。', '建议增加样本量（如达到题项数的5-10倍），检查并删除与其他题项相关性过低的题目，或重新评估题项内容是否准确反映工作满意度构念，可尝试探索性因子分析以优化题项结构。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('2940cb9a05034a81951356f54216cea4', 'b54e294b9cd04196b131da3e55787d2c', '职业发展', 'kmo', 0.5, 0.6, 'KMO值为0.5，低于0.6的可接受标准，说明该维度内题项间的共同因素较少，可能由于题目数量不足、维度内部一致性较低或存在测量误差较大的题目影响因子提取。', '建议增加样本量，对维度内题项进行项目分析，删除因子载荷较低或交叉载荷严重的题目，或根据理论考虑增加新的测量条目以提高维度结构清晰度。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('b67ef6f9cf964643bd5cb7a69195d504', '6e29c99ccbb543da8b2a7e797b8cb117', '', 'cumulative_variance', 0, 0, '命中翻车点 P07：未报累计方差解释率', '因子分析应报告累计方差解释率，以说明公因子对原变量的解释能力。请补充该指标。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('ad015db106ef4f36b94d3cb6a99e7642', '3e270a3a7c5e48a38c546463cd3d2f87', '', 'cumulative_variance', 0, 0, '命中翻车点 P07：未报累计方差解释率', '因子分析应报告累计方差解释率，以说明公因子对原变量的解释能力。请补充该指标。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('73d8892b996449f895d243653dd2f08c', '14ab0551813a4ed18b121c51f9b53139', '', 'cumulative_variance', 0, 0, '命中翻车点 P07：未报累计方差解释率', '因子分析应报告累计方差解释率，以说明公因子对原变量的解释能力。请补充该指标。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('28b48fc96f1340ad8062b3434ecf24c9', '336d58cd0c6f4f60a76424650b3bc79b', '', 'reverse_items', 0, 0, '命中翻车点 P01：反向题未反转', '存在反向题但未做反向计分，会导致 α 偏低甚至负值。请在数据预处理阶段反转反向题（如 6 减去原值），再重算信度。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('b5c985e4b1ce45edbe90eff25c978132', '336d58cd0c6f4f60a76424650b3bc79b', '', 'kmo', 0, 0, '命中翻车点 P04：KMO<0.5 仍强行做 EFA', 'KMO 低于 0.5 时数据不适合做因子分析，强行 EFA 会导致因子结构不稳定。建议先检查变量间相关性，或增加样本/调整题项后重测 KMO。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('8ba2d34094f948ef811177bca6f73f30', '336d58cd0c6f4f60a76424650b3bc79b', '', 'cumulative_variance', 0, 0, '命中翻车点 P07：未报累计方差解释率', '因子分析应报告累计方差解释率，以说明公因子对原变量的解释能力。请补充该指标。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('89065e91f9b14f1bb9276cc608b34ef4', '336d58cd0c6f4f60a76424650b3bc79b', '工作满意度', 'kmo', 0.5, 0.5, 'KMO值刚好处于临界下限，表明题项间共同方差偏低。可能是因为部分题项与其他题项相关性较弱，或样本量不足导致变量间关联性不稳定。', '建议增加样本量（当前样本量可能过小），同时检查每个题项与其他题项的相关系数，删除相关系数低于0.3的题项后重新计算KMO，或考虑调整量表结构。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('4d3045627dcb43a388c2ae16888e832b', '336d58cd0c6f4f60a76424650b3bc79b', '人际关系', 'alpha', 0, 0.7, 'Cronbach''s α为0，表明题项间内部一致性问题严重。可能原因包括：反向题未正确计分导致题项间负相关、题项表述歧义或与维度定义不符、题目数量过少（如不足3题）、或样本存在异常值。', '首先检查数据预处理是否完成反向题反转（如将反向题分数用最大值+1减去原值）；其次计算题项间相关矩阵，识别并删除与其他题项负相关或相关系数极低的题目；若题项数少于3个，需补充题目；同时检查是否有异常值或缺失值影响。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('0abd436218a54e94b4fa5ed1e209449d', '336d58cd0c6f4f60a76424650b3bc79b', '人际关系', 'kmo', 0, 0.5, 'KMO值为0，表明变量间几乎无共同方差，数据完全不适合做因子分析。通常因题项之间相互独立（相关系数接近0）或样本量严重不足导致。', '检查题项间相关系数矩阵，若大部分相关系数<0.1则需要重新设计量表；如果样本量极小（如<30），需收集更多样本；若题项间存在明显负相关，需检查反向题处理。在问题解决前不建议进行因子分析。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('691d0d9525d640e1b7b37927ddf3da10', '336d58cd0c6f4f60a76424650b3bc79b', '人际关系', 'bartlett_p', 1, 0.05, 'Bartlett球形检验p=1.0，完全不显著，说明相关矩阵为单位矩阵，变量之间相互独立，无法提取公因子。原因与KMO=0相同，即题项间缺乏相关性。', '与KMO问题同步解决：确保反向题正确反转，检查题项语义是否与维度一致，必要时删除或修改无相关性的题项，并增加样本量后重测。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('1e3ec16f4740437b8f7449e3e4d76ec1', '336d58cd0c6f4f60a76424650b3bc79b', '工作感受', 'alpha', 0, 0.7, 'Cronbach''s α为0，表明该维度题项之间内部一致性极差。常见原因包括反向题未反转导致负相关、题项内容偏离维度定义、或题目数量过少。', '核查数据中是否存在反向题并确认已反转；计算题项间相关系数，删除负相关或极低相关的题目；考虑增加2-3个与“工作感受”内涵一致的题目以提高信度。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('40b6367334624b799b790b554eac42bd', '336d58cd0c6f4f60a76424650b3bc79b', '工作感受', 'kmo', 0, 0.5, 'KMO为0，说明题项间无共同方差，无法进行因子分析。可能由于题项间完全独立，或样本量不足以估计相关结构。', '建议先检查每个题项与其他题项的相关系数，若多数接近0则需重新设计量表；若样本量不足，则扩大样本量至题项数的10倍以上。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('448c82fbaac04a44bc811847a50b667b', '336d58cd0c6f4f60a76424650b3bc79b', '工作感受', 'bartlett_p', 1, 0.05, 'Bartlett检验不显著，进一步验证了变量间不存在相关性，原因与KMO相同。', '与上述KMO问题一并处理：确保数据预处理正确，检查题项质量，增加样本或修改量表。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('62ae881acc234f7ab541c149a3c69291', '336d58cd0c6f4f60a76424650b3bc79b', '薪酬福利', 'alpha', 0, 0.7, '内部一致性信度为0，提示题项间可能存在负相关或完全无关。可能原因是该维度包含反向题但未反转，或题项表述不一致。', '确认所有反向题是否已正确反转；计算题项间相关矩阵，若出现负相关则重点检查反向题；若题项数不足3个，考虑增加题目。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('3602fad44061478b909da0adcee2807f', '336d58cd0c6f4f60a76424650b3bc79b', '薪酬福利', 'kmo', 0, 0.5, 'KMO值为0，数据不适合因子分析，通常因变量间独立或样本过小引起。', '检查样本量是否足够（建议>100），并计算题项间相关系数；若相关系数普遍偏低，需重新审视量表题项。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('1c5d4e1ef3d045a9b86a8ef0776bbd8a', '336d58cd0c6f4f60a76424650b3bc79b', '薪酬福利', 'bartlett_p', 1, 0.05, 'Bartlett检验p=1.0，说明相关矩阵为单位矩阵，无法提取因子。', '与KMO问题同步解决，确保题项间存在一定的相关性后再进行因子分析。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('ab41704b34c64b51a3fbe48102f88f4c', '336d58cd0c6f4f60a76424650b3bc79b', '职业发展', 'alpha', 0, 0.7, 'α为0，内部一致性差。可能由于反向题未处理、题项间方向不一、或题目内容无法反映同一构念。', '反向题反转后重算信度；若仍为0，则逐题检查题项是否属于同一维度，考虑删除或修改。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('dcfcffd7d19449e0a43c06dfb91c6a10', '336d58cd0c6f4f60a76424650b3bc79b', '职业发展', 'kmo', 0, 0.5, 'KMO=0，变量间无共同方差。', '检查样本量和题项相关性，剔除无相关题项。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('4f246fdc61c546a4939e20f21aa8b617', '336d58cd0c6f4f60a76424650b3bc79b', '职业发展', 'bartlett_p', 1, 0.05, 'Bartlett检验不显著，变量间独立。', '加强题项相关性构建，如修改题项措辞使其更聚焦于同一构念。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('4dc0cdea62054191a40b4de0642b71c4', '336d58cd0c6f4f60a76424650b3bc79b', '工作压力', 'alpha', 0, 0.7, '内部一致性信度为0，可能因反向题未反转或题项间相关系数过低。', '检查反向题反转情况；计算题项间相关系数，删除低相关题项；若题项数<3，需补充。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('2746be8d572d43a582e3fc83c35beb7c', '336d58cd0c6f4f60a76424650b3bc79b', '工作压力', 'kmo', 0, 0.5, 'KMO=0，不适合因子分析。', '增加样本量并优化题项。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('06e53ef8aee642a18e6819400b9b0577', '336d58cd0c6f4f60a76424650b3bc79b', '工作压力', 'bartlett_p', 1, 0.05, 'Bartlett检验不显著。', '与KMO问题一同处理。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('fdcb8105162d4875bf74ed89eac8321a', '336d58cd0c6f4f60a76424650b3bc79b', '组织认同', 'kmo', 0.5, 0.5, 'KMO值为0.5，处于临界下限，表明题项间共同度不足。可能由于部分题项与其他题项相关性较弱或样本量有限。', '建议增加样本量，并删除与维度内其他题项相关系数低于0.3的题目，以提高KMO值至0.6以上。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('7d64c1d354154f2a89a77b94c03fe4b7', '336d58cd0c6f4f60a76424650b3bc79b', '工作生活平衡', 'alpha', 0, 0.7, 'α为0，内部一致性极差，常见于反向题未正确处理或题项间缺乏相关性。', '检查反向题反转情况，计算相关系数并删除无关题项。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('2e6a35fe184a4d378d8c34a4b5023547', '336d58cd0c6f4f60a76424650b3bc79b', '工作生活平衡', 'kmo', 0, 0.5, 'KMO=0，数据不适合因子分析。', '检查样本量和题项质量。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('180b74ab95a44213bbd6476ea4734f95', '336d58cd0c6f4f60a76424650b3bc79b', '工作生活平衡', 'bartlett_p', 1, 0.05, 'Bartlett检验不显著，变量间独立。', '与KMO问题一起解决。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('15370b54dc1143a1b1fc75d06f408445', 'd623e39a55294d3cab0015884a3831c6', '', 'reverse_items', 0, 0, '命中翻车点 P01：反向题未反转', '存在反向题但未做反向计分，会导致 α 偏低甚至负值。请在数据预处理阶段反转反向题（如 6 减去原值），再重算信度。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('52cc772b1de2413cb1e93da34c5ac9c4', 'd623e39a55294d3cab0015884a3831c6', '', 'kmo', 0, 0, '命中翻车点 P04：KMO<0.5 仍强行做 EFA', 'KMO 低于 0.5 时数据不适合做因子分析，强行 EFA 会导致因子结构不稳定。建议先检查变量间相关性，或增加样本/调整题项后重测 KMO。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('e648577f93f24b5e9ff7274fa93104ba', 'd623e39a55294d3cab0015884a3831c6', '', 'cumulative_variance', 0, 0, '命中翻车点 P07：未报累计方差解释率', '因子分析应报告累计方差解释率，以说明公因子对原变量的解释能力。请补充该指标。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('e7fb04c607d0488096d015aedaa3a88f', 'd623e39a55294d3cab0015884a3831c6', '工作满意度', 'alpha', 0, 0.7, 'α值为0，表明题目间无任何内部一致性。可能原因：反向题未反转导致负相关被截断为0；或数据变异极小（所有被试回答相同或样本量过小）。', '检查数据预处理：确认所有反向题已正确反转（如6-原值）；查看每个题目的标准差，若为0则删除无效题目；确保样本量至少30-50以上，重新计算信度。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('0afe461c2fd44dc69c731aa21dade79a', 'd623e39a55294d3cab0015884a3831c6', '工作满意度', 'kmo', 0, 0.5, 'KMO为0，说明变量间偏相关系数极小，数据完全不适宜做因子分析。通常因变量间无相关或样本极端不足导致。', '先检查变量间Pearson相关系数，若多数接近0，需修订题目或重新收集数据；若样本量过小，需增加被试至至少100以上；同时检查数据录入错误。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('3b058420c7f7416293e527b7ef76c255', 'd623e39a55294d3cab0015884a3831c6', '工作满意度', 'bartlett_p', 1, 0.05, 'Bartlett球形检验p=1.0，表明相关矩阵为单位矩阵，变量间完全独立。常见原因：题目无变异（所有回答相同）、样本量极低或错误编码。', '核实数据矩阵是否包含有效差异；检查是否误用常量数据；若样本量小于变量数，需扩充样本；重新运行描述统计确认变量方差。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('edab4cebf89a422f99824a8b8ae32666', 'd623e39a55294d3cab0015884a3831c6', '人际关系', 'alpha', 0, 0.7, '同工作满意度维度，α=0表明内部一致性失效，可能是反向题未反转或数据无变异。', '检查反向题计分方向，确保所有题目计分方向一致；计算各题方差，剔除零方差题目；增加样本量后重算。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('cdd5e333aaad4c4cb421c3573f97a1e1', 'd623e39a55294d3cab0015884a3831c6', '人际关系', 'kmo', 0, 0.5, 'KMO=0，变量间无共享方差，无法进行因子分析。原因同上。', '检查题目间相关性，改善题目设计或重新收集数据；若样本量过小，扩大样本至合理规模。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('6aade1ab0fe9458a9a3c7743e786cd28', 'd623e39a55294d3cab0015884a3831c6', '人际关系', 'bartlett_p', 1, 0.05, 'p=1.0，数据不存在任何相关结构。可能因样本单一或数据录入格式错误。', '确认原始数据是否为数值型且包含足够变异；检查是否存在缺失值或异常值处理不当。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('d2659d72c95546cb94e7bddd6e08b8a6', 'd623e39a55294d3cab0015884a3831c6', '工作感受', 'alpha', 0, 0.7, 'α=0，表明题目间无一致性。可能原因：反向题未反转或数据无变异。', '重新审查该维度题项是否有反向表述并正确反转；计算项目-总分相关，删除相关为负或极低的题项。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('d1708c6c07ef457483e99e7e49d3f09c', 'd623e39a55294d3cab0015884a3831c6', '工作感受', 'kmo', 0, 0.5, 'KMO=0，不适合因子分析。原因同前。', '若相关矩阵对角元素远大于非对角，需修改量表设计；也可尝试删除低相关题目后再测KMO。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('59cc6dd00f5e4cc1b7529783e4bc1a0c', 'd623e39a55294d3cab0015884a3831c6', '工作感受', 'bartlett_p', 1, 0.05, 'Bartlett检验不显著，变量间独立。原因：数据无差异或样本量不足。', '核实样本量是否达到每题至少5-10倍的要求；检查是否所有题目答案相同。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('a4d857e2e0394d0a8e5220df1458dbbd', 'd623e39a55294d3cab0015884a3831c6', '薪酬福利', 'alpha', 0, 0.7, 'α=0，内部一致性缺失。', '检查该维度题目是否包含反向题，确保反转正确；若题目数量过少（如≤2），建议增加题目。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('23411105bb9343e689e65fbca09af74a', 'd623e39a55294d3cab0015884a3831c6', '薪酬福利', 'kmo', 0, 0.5, 'KMO=0，数据不适合因子分析。', '计算该维度题目的Spearman相关矩阵，若所有相关绝对值小于0.3，则需重新设计题目或调整施测。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('2ec6b8a6b8b54b8fb66dd5a09192b629', 'd623e39a55294d3cab0015884a3831c6', '薪酬福利', 'bartlett_p', 1, 0.05, 'p=1.0，无相关结构。', '检查是否有题项编码错误（如反向题未反转导致负相关被抵消）；若样本量<30，需扩充。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('1ea2cabff60e4e7096ad7805755bff67', 'd623e39a55294d3cab0015884a3831c6', '职业发展', 'alpha', 0, 0.7, 'α=0，信度极低。', '利用项目分析（如区分度）筛选题项；若全部题目方差为0，则数据无效，需重新收集。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('23976b4116b94bbfb2d31e4b3c066bc4', 'd623e39a55294d3cab0015884a3831c6', '职业发展', 'kmo', 0, 0.5, 'KMO=0。', '尝试使用修正后的项目-总相关大于0.3的题目重新计算KMO；若仍低，需修订量表。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('3db778be45b34824a50bdce5a23cade0', 'd623e39a55294d3cab0015884a3831c6', '职业发展', 'bartlett_p', 1, 0.05, 'Bartlett检验未通过。', '检查数据是否来自单一个体或所有值相同；重新运行描述统计确认均值与标准差。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('c5b8b7e621f641e19f41e2899cd31056', 'd623e39a55294d3cab0015884a3831c6', '工作压力', 'alpha', 0, 0.7, 'α=0。', '检查是否存在极端值或录入错误；若为反向题未反转，则反转后重新计算。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('68e49a9853514eaba86d578100dec916', 'd623e39a55294d3cab0015884a3831c6', '工作压力', 'kmo', 0, 0.5, 'KMO=0。', '确保样本量至少为变量数的5倍；如果变量数>样本量，则需收集更多数据。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('cc6ea701546f40e8afb4ad52f8da7614', 'd623e39a55294d3cab0015884a3831c6', '工作压力', 'bartlett_p', 1, 0.05, 'p=1.0。', '检查是否所有被试在本题组上只选择了同一选项；若是，则题目无效。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('5093ee76f22a4d9db8824749faab3aaf', 'd623e39a55294d3cab0015884a3831c6', '组织认同', 'alpha', 0, 0.7, 'α=0。', '检查该维度下题目是否均为正向表述，若有反向题请反转；同时检查样本量是否≥30。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('6f017e738e254d6aaf3f1562cffdf6c6', 'd623e39a55294d3cab0015884a3831c6', '组织认同', 'kmo', 0, 0.5, 'KMO=0。', '计算变量间相关系数矩阵，若大部分<0.1，建议修改量表或扩大样本。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('eed544ed55d34c769c7da02b30cdeb95', 'd623e39a55294d3cab0015884a3831c6', '组织认同', 'bartlett_p', 1, 0.05, 'p=1.0。', '确认数据是否因分列不当导致所有值相同；重新导入原始数据并检查格式。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('c90a420fdb1c496ba67757af2f2b3a2f', 'd623e39a55294d3cab0015884a3831c6', '工作生活平衡', 'alpha', 0, 0.7, 'α=0。', '使用SPSS或R的psych包计算信度时，请确认反向题已用''ReverseCode''函数处理；若仍为0，则数据不可信。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('f1a84ad2f4654614a20dff32695e80e6', 'd623e39a55294d3cab0015884a3831c6', '工作生活平衡', 'kmo', 0, 0.5, 'KMO=0。', '尝试删除该维度下与其他题目无相关的题项；若仅剩1题则不可做因子分析。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('ed30825739414eea84537db3ee7fc778', 'd623e39a55294d3cab0015884a3831c6', '工作生活平衡', 'bartlett_p', 1, 0.05, 'p=1.0。', '检查是否因为样本量过小或数据为常数导致；建议收集至少100份有效问卷后重测。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('ff0d333c665b4ef58566f0161e554c32', 'a4c725f76fe14232814b74523f7eb923', '', 'reverse_items', 0, 0, '命中翻车点 P01：反向题未反转', '存在反向题但未做反向计分，会导致 α 偏低甚至负值。请在数据预处理阶段反转反向题（如 6 减去原值），再重算信度。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('bd187b250019445ebeb0aeb2d1fd2f9b', 'a4c725f76fe14232814b74523f7eb923', '', 'kmo', 0, 0, '命中翻车点 P04：KMO<0.5 仍强行做 EFA', 'KMO 低于 0.5 时数据不适合做因子分析，强行 EFA 会导致因子结构不稳定。建议先检查变量间相关性，或增加样本/调整题项后重测 KMO。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('ceb7be2af8d644e5b612eb63ecd16a6b', 'a4c725f76fe14232814b74523f7eb923', '', 'cumulative_variance', 0, 0, '命中翻车点 P07：未报累计方差解释率', '因子分析应报告累计方差解释率，以说明公因子对原变量的解释能力。请补充该指标。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('3fb27195ac694ffba898c9d317ee7289', 'a4c725f76fe14232814b74523f7eb923', '工作满意度', 'alpha', 0, 0.7, 'Cronbach''s α 为 0.0，表明该维度内各条目之间完全不存在正相关，甚至可能因反向题未反转导致负相关被抵消。同时不排除数据录入错误、条目方差为零（如所有被试回答完全相同）或样本量过小（如 < 5）导致信度无法计算。', '1. 检查原始数据：确认该维度所有条目是否存在变异（即标准差 > 0）；2. 核对反向题的编码是否已正确反转（原值 → 6-原值）；3. 若样本量 < 30，建议补充样本至至少 50 人；4. 重算信度前，删除缺失值或常数条目。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('59b3c89730d248c6a7abda179e8311b9', 'a4c725f76fe14232814b74523f7eb923', '工作满意度', 'kmo', 0, 0.5, 'KMO 为 0.0，说明变量间偏相关系数平方和远大于简单相关系数平方和，数据完全不适合做因子分析。常见原因包括：变量间几乎无线性相关（可能因反向题未反转导致符号错乱）、条目方差为零、或样本量极低（< 样本数 < 变量数）。', '1. 计算各条目间 Pearson 相关矩阵，若多数相关系数 < 0.1，需检查数据质量；2. 确保所有条目为非定值且量尺一致（如均使用 1-5 Likert）；3. 增加样本量至条目数的 5-10 倍；4. 在反转反向题后重新计算 KMO。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('f79faabafc9144fe93123814fbc6521d', 'a4c725f76fe14232814b74523f7eb923', '工作满意度', 'bartlett_p', 1, 0.05, 'Bartlett 球形检验 p = 1.0（不显著），表明相关矩阵为单位矩阵，即变量间完全独立。这通常是数据被严重扭曲的信号：可能所有条目取值完全相同、被误设为常量、或反向题未反转导致正负相关抵消后整体相关为零。', '1. 确认数据是否已正确导入且数值范围合理；2. 绘制散点图矩阵，检查是否存在非线性关系或异常值；3. 若为定性数据（如分类变量），需改用多分格相关矩阵代替 Pearson 相关；4. 在反转反向题后重新运行检验。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('964abbf7a5c7431d84c57aec45ded0c7', 'a4c725f76fe14232814b74523f7eb923', '人际关系', 'alpha', 0, 0.7, 'Cronbach''s α 为 0.0，表明该维度内各条目之间完全不存在正相关，甚至可能因反向题未反转导致负相关被抵消。同时不排除数据录入错误、条目方差为零（如所有被试回答完全相同）或样本量过小（如 < 5）导致信度无法计算。', '1. 检查原始数据：确认该维度所有条目是否存在变异（即标准差 > 0）；2. 核对反向题的编码是否已正确反转（原值 → 6-原值）；3. 若样本量 < 30，建议补充样本至至少 50 人；4. 重算信度前，删除缺失值或常数条目。');
