INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('9be17b1a26724334bd65e0bbb76ba104', 'a4c725f76fe14232814b74523f7eb923', '工作生活平衡', 'alpha', 0, 0.7, 'Cronbach''s α 为 0.0，表明该维度内各条目之间完全不存在正相关，甚至可能因反向题未反转导致负相关被抵消。同时不排除数据录入错误、条目方差为零（如所有被试回答完全相同）或样本量过小（如 < 5）导致信度无法计算。', '1. 检查原始数据：确认该维度所有条目是否存在变异（即标准差 > 0）；2. 核对反向题的编码是否已正确反转（原值 → 6-原值）；3. 若样本量 < 30，建议补充样本至至少 50 人；4. 重算信度前，删除缺失值或常数条目。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('6291873349c24f21a28a8e08ab72f95b', 'a4c725f76fe14232814b74523f7eb923', '工作生活平衡', 'kmo', 0, 0.5, 'KMO 为 0.0，说明变量间偏相关系数平方和远大于简单相关系数平方和，数据完全不适合做因子分析。常见原因包括：变量间几乎无线性相关（可能因反向题未反转导致符号错乱）、条目方差为零、或样本量极低（< 样本数 < 变量数）。', '1. 计算各条目间 Pearson 相关矩阵，若多数相关系数 < 0.1，需检查数据质量；2. 确保所有条目为非定值且量尺一致（如均使用 1-5 Likert）；3. 增加样本量至条目数的 5-10 倍；4. 在反转反向题后重新计算 KMO。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('d5ec1af3f4574d809564efc8e11c6490', 'a4c725f76fe14232814b74523f7eb923', '工作生活平衡', 'bartlett_p', 1, 0.05, 'Bartlett 球形检验 p = 1.0（不显著），表明相关矩阵为单位矩阵，即变量间完全独立。这通常是数据被严重扭曲的信号：可能所有条目取值完全相同、被误设为常量、或反向题未反转导致正负相关抵消后整体相关为零。', '1. 确认数据是否已正确导入且数值范围合理；2. 绘制散点图矩阵，检查是否存在非线性关系或异常值；3. 若为定性数据（如分类变量），需改用多分格相关矩阵代替 Pearson 相关；4. 在反转反向题后重新运行检验。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('f0635a9d5cf74407b2ee3d8a729a4565', '8f35b2df0f8b4dd5905eae58d36b69d4', '', 'kmo', 0, 0, '命中翻车点 P04：KMO<0.5 仍强行做 EFA', 'KMO 低于 0.5 时数据不适合做因子分析，强行 EFA 会导致因子结构不稳定。建议先检查变量间相关性，或增加样本/调整题项后重测 KMO。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('1bb8fe5e9b4948ecb5f8d64fd9a1e9e5', '8f35b2df0f8b4dd5905eae58d36b69d4', '', 'cumulative_variance', 0, 0, '命中翻车点 P07：未报累计方差解释率', '因子分析应报告累计方差解释率，以说明公因子对原变量的解释能力。请补充该指标。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('46751dab79844a8b8e250321ebac5b72', '8f35b2df0f8b4dd5905eae58d36b69d4', '自我效能感', 'alpha', 0, 0.7, 'α=0.0极低，表明条目间完全没有正相关。可能原因：(1) 题目方向不一致（如未正确反向计分）；(2) 数据存在大量缺失或异常值；(3) 条目内容测量不同构念，内部一致性极差。', '检查条目计分方向是否一致，修正反向题计分；清洗数据中的缺失值和极端值；若题目间逻辑无关，需重新设计量表或删除低相关条目。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('6d883d18fd134b08902479ed86c7764d', '8f35b2df0f8b4dd5905eae58d36b69d4', '自我效能感', 'kmo', 0, 0.5, 'KMO=0.0表明变量间几乎无共同方差，不适合因子分析。可能原因：(1) 条目间相关性极弱或呈负相关；(2) 样本量过小（例如低于50）；(3) 数据中存在高度共线性或奇异值。', '检查相关矩阵，排除几乎无相关或负相关的条目；增加样本量（建议至少为题项数的10倍以上）；考虑删除或合并高相关条目后再测KMO。');
INSERT INTO diagnosis_issues (id, diagnosis_id, dimension, metric, "value", threshold, reason, suggestion) VALUES ('93490327b79549f4a86ca9a3d259d1c8', '8f35b2df0f8b4dd5905eae58d36b69d4', '自我效能感', 'bartlett_p', 1, 0.05, 'Bartlett球形检验p=1.0完全不显著，说明相关矩阵为单位矩阵，变量间独立。可能原因：(1) 题目间毫无关联；(2) 样本量极小导致检验效能不足；(3) 数据存在系统误差（如所有被试勾选同一选项）。', '检查数据应答模式（如是否出现全选极端值）；扩大样本量（建议至少100-200）；若条目确实彼此无关，则需重新构建维度或使用单题测量。');
